import {
  AGENT_PERSONA_MOOD_IDS,
  type AgentPersonaMoodId,
} from '@/shared/contracts/agents';
import type {
  PersonaMemoryRecord,
  PersonaMemorySourceType,
} from '@/shared/contracts/persona-memory';
import type { JsonValue } from '@/shared/contracts/json';

export const MOOD_ID_SET = new Set<AgentPersonaMoodId>(AGENT_PERSONA_MOOD_IDS);
export const STOP_WORDS = new Set([
  'about',
  'after',
  'again',
  'agent',
  'because',
  'before',
  'being',
  'chat',
  'could',
  'first',
  'from',
  'have',
  'into',
  'just',
  'lesson',
  'memory',
  'message',
  'more',
  'page',
  'practice',
  'should',
  'student',
  'than',
  'that',
  'their',
  'there',
  'these',
  'they',
  'this',
  'topic',
  'tutor',
  'when',
  'which',
  'with',
  'would',
]);

export const MOOD_KEYWORDS: Record<Exclude<AgentPersonaMoodId, 'neutral'>, string[]> = {
  thinking: ['think', 'consider', 'analyze', 'reason', 'step', 'reflect'],
  encouraging: ['keep going', 'you can', 'try again', 'practice', 'let us', 'let\'s', 'progress'],
  happy: ['glad', 'happy', 'pleased', 'delighted', 'enjoyed'],
  celebrating: ['great job', 'well done', 'congrat', 'excellent', 'amazing', 'celebrate'],
};

export const clamp = (value: number | undefined, min: number, max: number, fallback: number): number => {
  if (value === undefined || !Number.isFinite(value)) return fallback;
  return Math.min(max, Math.max(min, Math.round(value)));
};

export const asRecord = (
  value: JsonValue | null | undefined
): Record<string, unknown> | undefined => {
  if (value === null || value === undefined || typeof value !== 'object' || Array.isArray(value)) {
    return undefined;
  }
  return value as Record<string, unknown>;
};

export const normalizeText = (value: string): string => value.trim().replace(/\s+/g, ' ');

export type PersonaMemoryEntryRecord = {
  id: string;
  createdAt: Date | string;
  updatedAt: Date | string;
  runId: string | null;
  memoryKey: string | null;
  sourceType: string | null;
  sourceId: string | null;
  sourceLabel: string | null;
  sourceCreatedAt: Date | string | null;
  importance: number | null;
  tags: string[];
  topicHints: string[];
  moodHints: string[];
  content: string;
  summary: string | null;
  metadata: JsonValue | null;
  lastAccessedAt: Date | string | null;
};

export type PersonaConversationMessageRecord = {
  id: string;
  createdAt: Date | string;
  content: string;
  role: string;
  sessionId: string;
  model: string | null;
  images: unknown[];
  metadata: JsonValue | null;
  session: {
    id: string;
    title: string | null;
    createdAt: Date | string;
    updatedAt: Date | string;
  };
};

export const toIsoString = (value: Date | string | null | undefined): string | null => {
  if (value === null || value === undefined) return null;
  return value instanceof Date ? value.toISOString() : value;
};

const withEllipsis = (value: string, maxLength: number): string =>
  `${value.slice(0, maxLength - 1)}...`;

export const truncateText = (value: string, maxLength: number): string => {
  const normalized = normalizeText(value);
  return normalized.length <= maxLength ? normalized : withEllipsis(normalized, maxLength);
};

export const toTimestamp = (value?: string | null): number => {
  if (value === null || value === undefined) return 0;
  const timestamp = Date.parse(value);
  return Number.isNaN(timestamp) ? 0 : timestamp;
};

export const extractTopicHints = (text: string, fallback: string[] = []): string[] => {
  const tokens = normalizeText(text)
    .toLowerCase()
    .match(/[a-z0-9]{4,}/g);
  if (tokens === null) {
    return fallback.slice(0, 5);
  }

  const unique = new Set<string>(fallback.map((item) => item.toLowerCase()));
  for (const token of tokens) {
    if (STOP_WORDS.has(token)) continue;
    unique.add(token);
    if (unique.size >= 5) break;
  }
  return Array.from(unique).slice(0, 5);
};

export const inferMoodHintsFromText = (text: string): AgentPersonaMoodId[] => {
  const normalized = normalizeText(text).toLowerCase();
  const matches = Object.entries(MOOD_KEYWORDS)
    .filter(([, keywords]) => keywords.some((keyword) => normalized.includes(keyword)))
    .map(([moodId]) => moodId as AgentPersonaMoodId);
  return matches;
};

export const normalizeMoodHints = (
  moodHints: string[] | null | undefined,
  text: string
): AgentPersonaMoodId[] => {
  const normalized = Array.from(
    new Set(
      (moodHints ?? []).filter((moodId: string): moodId is AgentPersonaMoodId =>
        MOOD_ID_SET.has(moodId as AgentPersonaMoodId)
      )
    )
  );
  if (normalized.length > 0) return normalized;
  return inferMoodHintsFromText(text);
};

export const countSuggestedMood = (items: PersonaMemoryRecord[]): AgentPersonaMoodId | null => {
  const counts = new Map<AgentPersonaMoodId, number>();

  items.forEach((item) => {
    item.moodHints.forEach((moodId) => {
      counts.set(moodId, (counts.get(moodId) ?? 0) + 1);
    });
  });

  const ordered = Array.from(counts.entries()).sort((left, right) => right[1] - left[1]);
  return ordered[0]?.[0] ?? null;
};

export const resolveSourceTypeFilter = (
  sourceType: PersonaMemorySourceType | null | undefined
): { allowMessages: boolean; allowMemoryEntries: boolean } => {
  if (sourceType === null || sourceType === undefined) {
    return {
      allowMessages: true,
      allowMemoryEntries: true,
    };
  }

  if (sourceType === 'chat_message') {
    return {
      allowMessages: true,
      allowMemoryEntries: true,
    };
  }

  return {
    allowMessages: false,
    allowMemoryEntries: true,
  };
};

export const uniqueStrings = (values: Array<string | null | undefined>): string[] =>
  Array.from(
    new Set(
      values
        .map((value) => (typeof value === 'string' ? value.trim() : ''))
        .filter(Boolean)
    )
  );

export const uniqueLowercaseStrings = (values: Array<string | null | undefined>): string[] =>
  Array.from(
    new Set(
      values
        .map((value) => (typeof value === 'string' ? normalizeText(value).toLowerCase() : ''))
        .filter(Boolean)
    )
  );

export const buildSearchTerms = (value?: string | null): string[] =>
  uniqueLowercaseStrings([
    value ?? null,
    ...extractTopicHints(value ?? ''),
  ]);

const resolvePrimaryExtractedTopicHint = (value?: string | null): string | null =>
  extractTopicHints(value ?? '')[0] ?? null;

export const normalizeTopicFilter = (value?: string | null): string | null => {
  return (
    resolvePrimaryExtractedTopicHint(value) ??
    uniqueLowercaseStrings([value ?? null])[0] ??
    null
  );
};

export const matchesExactOrPartial = (values: string[], expected: string): boolean => {
  const normalizedExpected = normalizeText(expected).toLowerCase();
  return values.some((value) => {
    const normalizedValue = normalizeText(value).toLowerCase();
    return (
      normalizedValue === normalizedExpected ||
      normalizedValue.includes(normalizedExpected) ||
      normalizedExpected.includes(normalizedValue)
    );
  });
};

export const buildRecordSearchHaystacks = (item: PersonaMemoryRecord): string[] =>
  uniqueLowercaseStrings([
    item.content,
    item.summary ?? null,
    item.title ?? null,
    item.sourceLabel ?? null,
    item.role ?? null,
    ...item.tags,
    ...item.topicHints,
    ...item.moodHints,
  ]);

export const countMatchingSearchTerms = (item: PersonaMemoryRecord, searchTerms: string[]): number => {
  if (searchTerms.length === 0) {
    return 0;
  }

  const haystacks = buildRecordSearchHaystacks(item);
  return searchTerms.filter((term) => haystacks.some((value) => value.includes(term))).length;
};

export const matchesPersonaMemoryRecord = (
  item: PersonaMemoryRecord,
  filters: {
    tag: string | null;
    topic: string | null;
    mood: AgentPersonaMoodId | null;
    searchTerms: string[];
  }
): boolean => {
  const normalizedTags = uniqueLowercaseStrings(item.tags);

  if (filters.tag !== null && !matchesExactOrPartial(normalizedTags, filters.tag)) {
    return false;
  }

  if (filters.topic !== null && !matchesExactOrPartial(item.topicHints, filters.topic)) {
    return false;
  }

  if (filters.mood !== null && !item.moodHints.includes(filters.mood)) {
    return false;
  }

  if (filters.searchTerms.length > 0 && countMatchingSearchTerms(item, filters.searchTerms) === 0) {
    return false;
  }

  return true;
};

export const scorePersonaMemoryRecord = (
  item: PersonaMemoryRecord,
  filters: {
    tag: string | null;
    topic: string | null;
    mood: AgentPersonaMoodId | null;
    searchTerms: string[];
  }
): number => {
  let score = countMatchingSearchTerms(item, filters.searchTerms) * 10;

  if (filters.tag !== null && matchesExactOrPartial(item.tags, filters.tag)) {
    score += 8;
  }

  if (filters.topic !== null && matchesExactOrPartial(item.topicHints, filters.topic)) {
    score += 12;
  }

  if (filters.mood !== null && item.moodHints.includes(filters.mood)) {
    score += 10;
  }

  if (item.recordType === 'memory_entry') {
    score += 1;
  }

  return score;
};

export const mapMemoryEntryToRecord = (
  item: PersonaMemoryEntryRecord,
  personaId: string
): PersonaMemoryRecord => {
  const metadata = asRecord(item.metadata);
  let role: string | null = null;
  if (typeof metadata?.['role'] === 'string') {
    role = metadata['role'];
  } else if (typeof metadata?.['originRole'] === 'string') {
    role = metadata['originRole'];
  }

  const sourceTypeValue = (item.sourceType ?? 'agent_memory') as PersonaMemorySourceType;
  const sourceCreatedAtStr = toIsoString(item.sourceCreatedAt);
  const metadataSourceCreatedAt = metadata?.['sourceCreatedAt'];

  let sourceCreatedAt: string | null = sourceCreatedAtStr;
  if (sourceCreatedAt === null && typeof metadataSourceCreatedAt === 'string') {
    sourceCreatedAt = metadataSourceCreatedAt;
  }

  let title: string = truncateText(item.content, 80);
  if (item.sourceLabel !== null) {
    title = item.sourceLabel;
  } else if (item.summary !== null) {
    title = item.summary;
  }

  const lastAccessedAt = item.lastAccessedAt !== null ? toIsoString(item.lastAccessedAt) : null;

  return {
    id: item.id,
    createdAt: toIsoString(item.createdAt) ?? new Date().toISOString(),
    updatedAt: toIsoString(item.updatedAt) ?? new Date().toISOString(),
    personaId,
    recordType: 'memory_entry',
    content: item.content,
    summary: item.summary,
    title,
    role,
    sessionId:
      typeof metadata?.['sessionId'] === 'string' ? metadata['sessionId'] : item.runId,
    memoryKey: item.memoryKey,
    sourceType: sourceTypeValue,
    sourceId: item.sourceId ?? item.id,
    sourceLabel: item.sourceLabel,
    sourceCreatedAt,
    importance: item.importance,
    tags: item.tags,
    topicHints: extractTopicHints(item.summary ?? item.content, item.topicHints),
    moodHints: normalizeMoodHints(item.moodHints, item.summary ?? item.content),
    metadata: {
      ...(metadata ?? {}),
      ...(item.runId !== null ? { runId: item.runId } : {}),
      ...(lastAccessedAt !== null ? { lastAccessedAt } : {}),
    },
  };
};

export const mapConversationMessageToRecord = (
  message: PersonaConversationMessageRecord,
  personaId: string
): PersonaMemoryRecord => {
  const metadata = asRecord(message.metadata);
  const rawMoodHints = metadata?.['moodHints'];
  const moodHints = normalizeMoodHints(
    Array.isArray(rawMoodHints)
      ? rawMoodHints.filter((item): item is string => typeof item === 'string')
      : [],
    message.content
  );

  return {
    id: message.id,
    createdAt: toIsoString(message.createdAt) ?? new Date().toISOString(),
    updatedAt: toIsoString(message.createdAt) ?? new Date().toISOString(),
    personaId,
    recordType: 'conversation_message',
    content: message.content,
    summary: truncateText(message.content, 140),
    title: `${message.role === 'assistant' ? 'Assistant' : 'User'} message`,
    role: message.role,
    sessionId: message.sessionId,
    memoryKey: null,
    sourceType: 'chat_message',
    sourceId: message.id,
    sourceLabel: message.session.title ?? 'Untitled session',
    sourceCreatedAt: toIsoString(message.createdAt),
    importance: null,
    tags: [],
    topicHints: extractTopicHints(message.content),
    moodHints,
    metadata: {
      ...(metadata ?? {}),
      sessionTitle: message.session.title,
      ...(message.model !== null ? { model: message.model } : {}),
      ...(message.images.length > 0 ? { images: message.images } : {}),
    },
  };
};

export const formatMemoryPromptLine = (item: PersonaMemoryRecord): string => {
  const provenance = [
    item.recordType === 'conversation_message' ? 'chat history' : 'memory',
    item.sourceType ?? 'unknown-source',
    item.sourceLabel !== null ? `from "${item.sourceLabel}"` : null,
    item.sourceCreatedAt !== null ? `original ${item.sourceCreatedAt}` : null,
    `captured ${item.createdAt}`,
  ]
    .filter((part): part is string => part !== null)
    .join(' | ');

  return `- ${provenance}: ${truncateText(item.summary ?? item.content, 220)}`;
};
